final:
module top_module(
  input reset,
  input clk,
  output rst_sync
);parameter n = 2; // number of cycles that reset must be stable

reg [1:0] async_reset_filtered; // two-stage synchronizer

always @(posedge clk) begin
  async_reset_filtered[0] <= reset;
  async_reset_filtered[1] <= async_reset_filtered[0];
end

assign rst_sync = async_reset_filtered[1];

endmodule
